UPDATE tb_user
SET email = CONCAT(SUBSTRING(email, 1, LOCATE('@', email) - 1), '@autostradaauctions.local')
WHERE LOWER(email) LIKE '%@subotinmotors.local';

UPDATE tb_car_picture
SET image = ''
WHERE file_name LIKE 'demo-car-%';

UPDATE tb_car_listing_picture
SET image = ''
WHERE file_name LIKE 'demo-listing-%';
